// Single-node pipeline up to scoring:
//   read config + resumes  →  fetch each board (parallel, in-node via https)
//   →  normalize  →  filter  →  dedup  →  route resume  →  attach prompt
//
// Uses Node's built-in https module instead of fetch(), because n8n's task
// runner sandbox (introduced in 2.x) strips fetch from the global scope.
// `https` works because it's added to NODE_FUNCTION_ALLOW_BUILTIN in compose.

const fs = require('fs');
const https = require('https');
const http = require('http');

const root = '/data';
const readJson = (p) => JSON.parse(fs.readFileSync(`${root}/${p}`, 'utf8'));
const readText = (p) => fs.readFileSync(`${root}/${p}`, 'utf8');

const sources = readJson('config/sources.json');
const filters = readJson('config/filters.json');
const routing = readJson('config/resume_routing.json');

const resumes = {};
for (const f of fs.readdirSync(`${root}/resumes`)) {
  if (f.endsWith('.txt')) resumes[f] = readText(`resumes/${f}`);
}

const lower = (s) => (s || '').toString().toLowerCase();
const strip = (html) => (html || '').replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/gi, ' ').replace(/\s+/g, ' ').trim();

// --- FETCH (parallel, via Node built-in https/http) ----------------------
const getJson = (url) => new Promise((resolve, reject) => {
  const client = url.startsWith('https') ? https : http;
  const req = client.get(url, {
    headers: { 'Accept': 'application/json', 'User-Agent': 'pm-job-hunter/1.0' },
    timeout: 15000,
  }, (res) => {
    if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
      // follow one redirect hop
      return resolve(getJson(new URL(res.headers.location, url).toString()));
    }
    let chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      const body = Buffer.concat(chunks).toString('utf8');
      if (res.statusCode < 200 || res.statusCode >= 300) {
        return reject(new Error(`HTTP ${res.statusCode}`));
      }
      try { resolve(JSON.parse(body)); }
      catch (e) { reject(new Error('JSON parse failed: ' + e.message)); }
    });
  });
  req.on('timeout', () => { req.destroy(); reject(new Error('timeout')); });
  req.on('error', (e) => reject(e));
});

const fetchOne = async (b) => {
  try {
    const data = await getJson(b.fetch_url);
    return { ok: true, data, src: b };
  } catch (e) {
    return { ok: false, error: String(e?.message || e), src: b };
  }
};

const responses = await Promise.all((sources.boards || []).map(fetchOne));

// --- NORMALIZE -----------------------------------------------------------
const normalize = ({ data, src }) => {
  const out = [];
  if (!data) return out;
  if (src.board_type === 'greenhouse') {
    for (const j of (data.jobs || [])) {
      out.push({
        id: `gh:${src.slug}:${j.id}`,
        title: j.title || '',
        company: src.company,
        location: j.location?.name || '',
        url: j.absolute_url || '',
        jd: strip(j.content || ''),
        region: src.region,
      });
    }
  } else if (src.board_type === 'lever') {
    const jobs = Array.isArray(data) ? data : [];
    for (const j of jobs) {
      const jd = [j.descriptionPlain, ...(j.lists || []).map(l => `${l.text || ''}: ${strip(l.content || '')}`)].filter(Boolean).join('\n');
      out.push({
        id: `lv:${src.slug}:${j.id}`,
        title: j.text || '',
        company: src.company,
        location: j.categories?.location || j.workplaceType || '',
        url: j.hostedUrl || j.applyUrl || '',
        jd,
        region: src.region,
      });
    }
  } else if (src.board_type === 'ashby') {
    for (const j of (data.jobs || [])) {
      const secondaryStrs = (j.secondaryLocations || []).map(s => (typeof s === 'string' ? s : (s?.location || s?.name || ''))).filter(Boolean);
      const locBits = [j.location || '', j.workplaceType || '', ...secondaryStrs];
      if (j.isRemote) locBits.push('remote');
      const location = locBits.filter(Boolean).join(' | ');
      const jd = j.descriptionPlain || strip(j.descriptionHtml);
      out.push({
        id: `ab:${src.slug}:${j.id}`,
        title: j.title || '',
        company: src.company,
        location,
        url: j.jobUrl || j.applyUrl || '',
        jd,
        region: src.region,
      });
    }
  } else if (src.board_type === 'smartrecruiters') {
    for (const j of (data.content || [])) {
      const loc = j.location || {};
      const locBits = [loc.fullLocation, loc.city, loc.region, loc.country];
      if (loc.remote) locBits.push('remote');
      if (loc.hybrid) locBits.push('hybrid');
      const location = locBits.filter(Boolean).join(' | ');
      out.push({
        id: `sr:${src.slug}:${j.id}`,
        title: j.name || '',
        company: src.company,
        location,
        url: `https://jobs.smartrecruiters.com/${src.slug}/${j.id}`,
        jd: '',
        region: src.region,
      });
    }
  }
  return out;
};

const allJobs = responses.flatMap(r => r.ok ? normalize(r) : []);

// --- FILTER --------------------------------------------------------------
const { title_include, title_exclude, allowed_locations, remote_exclude_patterns, min_llm_score } = filters;
const allowedLocs = [
  ...allowed_locations.india,
  ...allowed_locations.middle_east,
  ...allowed_locations.remote_friendly,
];

const passesTitle = (t) => {
  const lt = lower(t);
  if (title_exclude.some(x => lt.includes(x))) return false;
  return title_include.some(x => lt.includes(x));
};
const passesLocation = (loc, jd) => {
  const hay = `${lower(loc)} || ${lower(jd).slice(0, 400)}`;
  if (!allowedLocs.some(x => hay.includes(x))) return false;
  if (lower(loc).includes('remote') && remote_exclude_patterns.some(p => lower(jd).includes(p))) return false;
  return true;
};

const afterFilter = allJobs.filter(j => passesTitle(j.title) && passesLocation(j.location, j.jd));

// --- DEDUP (workflow-scoped persistent state) ----------------------------
const staticData = $getWorkflowStaticData('global');
staticData.seen = staticData.seen || {};
const today = new Date().toISOString().slice(0, 10);
const afterDedup = afterFilter.filter(j => !staticData.seen[j.id]);
for (const j of afterDedup) staticData.seen[j.id] = today;

// --- ZERO-ITEM HANDLING --------------------------------------------------
// Distinguish two zero cases:
//   1) Boards/filter broken    → throw with diagnostics so we notice
//   2) Everything already seen → return [] silently; daily cron no-ops
if (afterDedup.length === 0) {
  if (afterFilter.length > 0) return [];   // normal: all matches already delivered
  const board_summary = responses.map(r => ({
    company: r.src.company,
    board_type: r.src.board_type,
    ok: r.ok,
    error: r.error,
    raw_count: r.ok
      ? (r.src.board_type === 'greenhouse'
          ? (r.data?.jobs?.length || 0)
          : (Array.isArray(r.data) ? r.data.length : 0))
      : 0,
  }));
  const diag = {
    boards: board_summary,
    raw_total: allJobs.length,
    after_filter: afterFilter.length,
    after_dedup: afterDedup.length,
    seen_size: Object.keys(staticData.seen).length,
  };
  throw new Error('Zero jobs after filter (boards or filter likely broken). DIAG: ' + JSON.stringify(diag));
}

// --- RESUME ROUTING ------------------------------------------------------
const pickResume = (job) => {
  const hay = `${lower(job.title)} ${lower(job.jd)}`.slice(0, 4000);
  for (const rule of routing.rules) {
    if (rule.match_any.some(k => hay.includes(lower(k)))) return rule.use_resume;
  }
  return routing.default_resume;
};

for (const j of afterDedup) {
  j.resume_file = pickResume(j);
  j.resume_text = resumes[j.resume_file] || resumes[routing.default_resume] || '';
  j._min_score = min_llm_score ?? 7;
}

return afterDedup.map(j => ({ json: j }));

// Build the Groq (OpenAI-compatible) request body for each job.
return $input.all().map(it => {
  const j = it.json;
  const system = 'You score job fit and return ONLY a JSON object. No prose, no markdown, no code fences.';
  const user = `Scoring rubric (return JSON: {"score": <1-10 integer>, "verdict": "<one short sentence>", "must_have_gaps": ["..."]}):\n- 10 = strong match on role (Product Management), seniority, domain, AND location (India / Middle East / India-friendly remote).\n- Penalise heavily if the role is non-PM (engineering, marketing, ops, design, data) or seniority is far below the candidate.\n- Penalise if location is remote but region-locked outside India/GCC.\n- Reward domain overlap (fintech, payments, BFSI, AI/ML, conversational AI, KYC/KYB).\n\nRESUME:\n${j.resume_text}\n\nJOB:\nTitle: ${j.title}\nCompany: ${j.company}\nLocation: ${j.location}\nJD:\n${(j.jd || '').slice(0, 3000)}`;

  return {
    json: {
      ...j,
      _prompt: user,
      _llm_body: {
        model: 'llama-3.3-70b-versatile',
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
        temperature: 0.2,
        max_tokens: 256,
        response_format: { type: 'json_object' },
      }
    }
  };
});

// Pair each LLM response with its originating job item (same node, same exec
// → 1:1 order preserved), parse the score, keep score ≥ threshold, build digest.
const jobs = $('Build LLM prompts').all().map(i => i.json);
const responses = $input.all().map(i => i.json);
const threshold = jobs[0]?._min_score ?? 7;

// Pull the LLM text payload from OpenAI-compatible (Groq) or Gemini-style responses.
const extractText = (r) => {
  if (!r || typeof r !== 'object') return '';
  // OpenAI / Groq shape
  const o1 = r?.choices?.[0]?.message?.content;
  if (typeof o1 === 'string' && o1.length) return o1;
  const o2 = r?.body?.choices?.[0]?.message?.content;
  if (typeof o2 === 'string' && o2.length) return o2;
  const o3 = r?.data?.choices?.[0]?.message?.content;
  if (typeof o3 === 'string' && o3.length) return o3;
  // Surface API errors so they show up in the verdict
  const errMsg = r?.error?.message || r?.body?.error?.message || r?.data?.error?.message;
  if (errMsg) return `__ERROR__: ${errMsg}`;
  // Gemini-style fallback (in case we ever swap back)
  const g1 = r?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (typeof g1 === 'string' && g1.length) return g1;
  if (typeof r?.text === 'string') return r.text;
  return '';
};

// Tolerant JSON parse: strips ```json fences, finds the outermost {...},
// and falls back to a regex sweep for score/verdict if JSON.parse still fails.
const parseScore = (s) => {
  if (!s) return null;
  let cleaned = s.trim();
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
  // pull the first balanced-looking object substring
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start >= 0 && end > start) cleaned = cleaned.slice(start, end + 1);
  try { return JSON.parse(cleaned); } catch {}
  // last-resort: regex extract
  const scoreM = s.match(/"score"\s*:\s*(\d+(?:\.\d+)?)/);
  const verdictM = s.match(/"verdict"\s*:\s*"([^"]*)"/);
  if (scoreM) return { score: Number(scoreM[1]), verdict: verdictM?.[1] || '' };
  return null;
};

const scored = jobs.map((j, idx) => {
  const r = responses[idx] || {};
  const txt = extractText(r);
  const parsed = parseScore(txt);
  if (!parsed) {
    // expose raw shape for one item so failures are visible in Telegram digest
    return { ...j, score: 0, verdict: `parse failed; raw[0..120]=${txt.slice(0, 120).replace(/\n/g, ' ')}` };
  }
  return { ...j, score: Number(parsed.score) || 0, verdict: parsed.verdict || '' };
}).filter(j => j.score >= threshold)
  .sort((a, b) => b.score - a.score);

if (scored.length === 0) {
  return [{ json: { _skip: true, message: '', count: 0 } }];
}

const d = new Date();
const dateStr = d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

// Build per-job message blocks (with verdict capped so a single job can't blow the message budget)
const jobBlocks = scored.slice(0, 30).map((j, i) => {
  const v = (j.verdict || '').slice(0, 180);
  const block = [`${i + 1}. ${j.title} — ${j.company} (${j.location}) ★ ${j.score}/10`];
  if (v) block.push(`   ${v}`);
  block.push(`   → ${j.url}`);
  return block.join('\n');
});

// Pack blocks into chunks <= MAX chars each, leaving headroom for header/footer
const MAX = 3500;
const header = `🎯 PM Jobs — ${dateStr}\n${scored.length} match${scored.length === 1 ? '' : 'es'} (score ≥ ${threshold})\n`;
const footer = '\nSent by your job bot 🤖';

const chunks = [];
let body = '';
for (const block of jobBlocks) {
  const candidate = body ? body + '\n\n' + block : block;
  if ((header.length + candidate.length + footer.length) > MAX && body) {
    chunks.push(body);
    body = block;
  } else {
    body = candidate;
  }
}
if (body) chunks.push(body);

// Annotate with part numbers if we ended up with multiple messages
const messages = chunks.map((body, i) => {
  const partTag = chunks.length > 1 ? ` (part ${i + 1}/${chunks.length})` : '';
  return `🎯 PM Jobs — ${dateStr}${partTag}\n${scored.length} match${scored.length === 1 ? '' : 'es'} (score ≥ ${threshold})\n\n${body}${i === chunks.length - 1 ? footer : ''}`;
});

return messages.map(m => ({ json: { _skip: false, message: m, count: scored.length } }));
